public class StackFrameDemo {

    static int add(int a, int b) {
        int result = a + b;     // 'result' lives in add()'s frame
        return result;
    }

    static int multiply(int x, int factor) {
        int doubled = add(x, x);          // new frame for add() pushed
        int product = doubled * factor;    // 'product' in multiply()'s frame
        return product;
    }

    public static void main(String[] args) {
        int base = 5;           // in main()'s frame
        int result = multiply(base, 3);  // new frame for multiply() pushed
        System.out.println(result); // 30
    }
}

// Stack state during add() execution:
// Frame 3 [add()]       : a=5, b=5, result=10       <- top of stack
// Frame 2 [multiply()]  : x=5, factor=3, doubled=? product=?
// Frame 1 [main()]      : base=5, result=?

public class HeapLifecycleDemo {

    static class Config {
        String host;
        int port;
        Config(String h, int p) { host = h; port = p; }
    }

    static Config createConfig() {
        Config c = new Config("localhost", 8080); // allocated on heap
        return c;  // reference returned — object survives method return!
    }

    public static void main(String[] args) {
        // Object created inside createConfig() — but survives because reference returned
        Config cfg = createConfig();
        System.out.println(cfg.host + ":" + cfg.port); // localhost:8080

        // Object becomes GC-eligible when last reference gone
        cfg = null;  // or cfg goes out of scope at end of main()
        // Config object is now unreachable — eligible for GC

        // Short-lived objects: eligible immediately after block
        {
            Config temp = new Config("192.168.1.1", 9090); // heap
            System.out.println(temp.host);
        } // temp out of scope — Config@9090 eligible for GC

        System.out.println("cfg is null, temp gone");
    }
}

public class StackOverflowDemo {

    // BAD: infinite recursion — no base case
    static int infiniteCount(int n) {
        return infiniteCount(n + 1);  // never stops!
    }

    // GOOD: bounded recursion
    static int countdown(int n) {
        if (n <= 0) return 0;         // base case
        return 1 + countdown(n - 1);
    }

    // Maximum safe recursion depth (JVM-dependent, ~5000-10000 for default -Xss)
    static int maxDepth(int current) {
        try {
            return maxDepth(current + 1);
        } catch (StackOverflowError e) {
            return current;  // catch the error to find the depth
        }
    }

    public static void main(String[] args) {
        // Safe recursion
        System.out.println(countdown(10)); // 10

        // Find max recursion depth
        System.out.println("Max depth ~" + maxDepth(0));

        // This would crash:
        // infiniteCount(0); // StackOverflowError!
    }
}
// StackOverflowError thrown when stack is full
// Each frame for infiniteCount needs ~100-200 bytes
// Default stack size (Xss): ~512KB → ~2000-5000 frames

public class GcPressureDemo {

    // BAD: creates massive GC pressure
    static String joinStringsBad(String[] words) {
        String result = "";
        for (String w : words) {
            result = result + w + ","; // new String object per iteration!
        }
        return result;
    }

    // GOOD: single StringBuilder on heap, only 1 final String created
    static String joinStringsGood(String[] words) {
        StringBuilder sb = new StringBuilder();
        for (String w : words) {
            sb.append(w).append(","); // modifies same StringBuilder
        }
        return sb.toString(); // 1 final String allocation
    }

    // EVEN BETTER for large arrays:
    static String joinStringsJava(String[] words) {
        return String.join(",", words); // internally uses optimized joining
    }

    public static void main(String[] args) throws Exception {
        String[] words = new String[10_000];
        for (int i = 0; i < words.length; i++) words[i] = "word" + i;

        long t1 = System.currentTimeMillis();
        joinStringsBad(words);   // ~10,000 String objects allocated then GC'd
        System.out.println("Bad : " + (System.currentTimeMillis() - t1) + "ms");

        long t2 = System.currentTimeMillis();
        joinStringsGood(words);  // 1 StringBuilder + 1 final String
        System.out.println("Good: " + (System.currentTimeMillis() - t2) + "ms");
    }
}

