public class MemoryLeakDemo {

    // LEAK: static cache grows forever — objects never released
    static Map<String, byte[]> cache = new HashMap<>();

    static void processRequest(String key) {
        // Simulates caching large data
        cache.put(key, new byte[1024 * 1024]); // 1 MB per entry
        // Nobody ever removes entries!
    }

    // FIX 1: Bounded cache with explicit eviction
    static Map<String, byte[]> boundedCache = new LinkedHashMap<>(100, 0.75f, true) {
        @Override
        protected boolean removeEldestEntry(Map.Entry<String, byte[]> eldest) {
            return size() > 100; // evict when over 100 entries
        }
