import java.util.*;

public class Q13 {
    public static int iterativeDFS(List<List<Integer>> graph, int start) {
        boolean[] visited = new boolean[graph.size()];
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(start);
        int count = 0;
        while (!stack.isEmpty()) {
            int node = stack.pop();
            if (visited[node]) continue;
            visited[node] = true;
            count++;
            for (int neighbor : graph.get(node))
                if (!visited[neighbor]) stack.push(neighbor);
        }
        return count;
    }
    public static void main(String[] args) {
        List<List<Integer>> g = new ArrayList<>();
        for (int i = 0; i < 5; i++) g.add(new ArrayList<>());
        g.get(0).addAll(List.of(1, 2));
        g.get(1).add(3);
        g.get(2).add(4);
        System.out.println(iterativeDFS(g, 0)); // 5
    }
}

