import java.util.*;

public class Q14 {
    static class StringBuilderPool {
        private final Deque<StringBuilder> pool = new ArrayDeque<>();

        public StringBuilderPool(int size) {
            for (int i = 0; i < size; i++) pool.addLast(new StringBuilder());
        }

        public StringBuilder acquire() {
            return pool.pollFirst();
        }

        public void release(StringBuilder sb) {
            sb.setLength(0); // reset content
            pool.addFirst(sb);
        }

        public int available() { return pool.size(); }
    }

    public static void main(String[] args) {
        StringBuilderPool pool = new StringBuilderPool(3);
        System.out.println(pool.available()); // 3
        StringBuilder sb = pool.acquire();
        sb.append("Hello");
        System.out.println(pool.available()); // 2
        pool.release(sb);
        System.out.println(pool.available()); // 3
        System.out.println(pool.acquire().length()); // 0
    }
}

