import java.math.BigInteger;
import java.util.function.Supplier;

public class Q15 {
    @SuppressWarnings("unchecked")
    public static Object trampoline(Supplier<Object> thunk) {
        Object result = thunk;
        while (result instanceof Supplier) {
            result = ((Supplier<Object>) result).get();
        }
        return result;
    }

    static Supplier<Object> factHelper(BigInteger n, BigInteger acc) {
        if (n.compareTo(BigInteger.ONE) <= 0) return () -> acc; // final value
        return () -> factHelper(n.subtract(BigInteger.ONE), acc.multiply(n)); // next thunk
    }

    public static BigInteger factorial(int n) {
        return (BigInteger) trampoline(() -> factHelper(BigInteger.valueOf(n), BigInteger.ONE));
    }

    public static void main(String[] args) {
        System.out.println(factorial(10));   // 3628800
        System.out.println(factorial(100).toString().length() + " digits"); // 158 digits
    }
}

