public class Q17 {
    static class ArrayStack<T> {
        private final Object[] data;
        private int top = -1;

        public ArrayStack(int capacity) {
            data = new Object[capacity];
        }

        public void push(T item) {
            if (isFull()) throw new IllegalStateException("Stack overflow");
            data[++top] = item;
        }

        @SuppressWarnings("unchecked")
        public T pop() {
            if (isEmpty()) throw new IllegalStateException("Stack underflow");
            T val = (T) data[top];
            data[top--] = null; // help GC
            return val;
        }

        @SuppressWarnings("unchecked")
        public T peek() {
            if (isEmpty()) throw new IllegalStateException("Empty");
            return (T) data[top];
        }

        public boolean isEmpty() { return top == -1; }
        public boolean isFull()  { return top == data.length - 1; }
        public int size()        { return top + 1; }
    }

    public static void main(String[] args) {
        ArrayStack<Integer> s = new ArrayStack<>(3);
        s.push(1); s.push(2); s.push(3);
        System.out.println(s.isFull());  // true
        System.out.println(s.pop());     // 3
        System.out.println(s.peek());    // 2
        System.out.println(s.size());    // 2
    }
}

