public class Q18 {
    static class Point { double x, y; Point(double x, double y){this.x=x;this.y=y;} }

    // Object ESCAPES — returned to caller — must be heap-allocated
    public static Point doesEscape(double x, double y) {
        return new Point(x, y); // JVM cannot stack-allocate — reference escapes
    }

    // Object does NOT escape — JIT's escape analysis may stack-allocate
    // Enable with: -XX:+DoEscapeAnalysis (default on in Java 6+)
    public static double doesNotEscape(double x1, double y1, double x2, double y2) {
        Point p1 = new Point(x1, y1); // used locally only
        Point p2 = new Point(x2, y2); // used locally only
        double dx = p2.x - p1.x;
        double dy = p2.y - p1.y;
        return Math.sqrt(dx*dx + dy*dy); // only double escapes — p1 and p2 don't
    }

    public static void main(String[] args) {
        Point p = doesEscape(1.0, 2.0);
        System.out.println(p.x + "," + p.y); // 1.0,2.0
        System.out.println(doesNotEscape(0, 0, 3, 4)); // 5.0
    }
}

