public class Q19 {
    public static void transposeInPlace(int[][] matrix) {
        int n = matrix.length;
        for (int i = 0; i < n; i++)
            for (int j = i + 1; j < n; j++) {
                int tmp = matrix[i][j];
                matrix[i][j] = matrix[j][i];
                matrix[j][i] = tmp;
            }
    }
    public static void main(String[] args) {
        int[][] m = {{1,2,3},{4,5,6},{7,8,9}};
        transposeInPlace(m);
        for (int[] row : m) System.out.println(java.util.Arrays.toString(row));
        // [1, 4, 7]
        // [2, 5, 8]
        // [3, 6, 9]
    }
}

