import java.util.*;

public class Q20 {
    public static String causeOOM(int chunkSizeKB) {
        List<byte[]> list = new ArrayList<>();
        long allocated = 0;
        try {
            while (true) {
                list.add(new byte[chunkSizeKB * 1024]);
                allocated += chunkSizeKB * 1024L;
            }
        } catch (OutOfMemoryError e) {
            long maxHeap = Runtime.getRuntime().maxMemory();
            return String.format("OOM after %d MB allocated. Max heap: %d MB",
                allocated / (1024*1024),
                maxHeap / (1024*1024));
        }
    }
    public static void main(String[] args) {
        // Run with -Xmx64m to see OOM quickly
        System.out.println(causeOOM(10));
        // e.g.: OOM after 58 MB allocated. Max heap: 64 MB
    }
}
